// ========================================
// UNIVERSAL - DIAGNOSTIC LOGGING
// ========================================
// Map change and boss information logging
// Requires: _lastMapId variable in class config

private void LogMapChange(int currentMapId)
{
    if (_lastMapId != 0 && _lastMapId != currentMapId)
    {
        Log("Map changed: " + _lastMapId + " -> " + currentMapId);
    }
    _lastMapId = currentMapId;
}

private void LogBossInformation()
{
    for (int i = 1; i <= 4; i++)
    {
        string boss = "boss" + i;

        // Check if boss exists (has health > 0)
        int bossHealth = Inferno.Health(boss);
        if (bossHealth > 0)
        {
            // Get boss name (Retail only, so wrap in try-catch for safety)
            string bossName = "Unknown";
            try
            {
                bossName = Inferno.UnitName(boss);
            }
            catch { }

            // Get casting ID (0 if not casting)
            int castingId = Inferno.CastingID(boss);

            // Build log message
            string logMsg = "Boss" + i + ": " + bossName + " Health: " + bossHealth + "%";

            // If boss is casting, add casting information
            if (castingId != 0)
            {
                string castName = "Unknown";
                try
                {
                    castName = Inferno.CastingName(boss);
                }
                catch { }

                bool interruptable = Inferno.IsInterruptable(boss);
                bool channeling = Inferno.IsChanneling(boss);
                int elapsed = Inferno.CastingElapsed(boss);
                int remaining = Inferno.CastingRemaining(boss);

                logMsg += " | CASTING: " + castName + " (ID:" + castingId + ")";
                logMsg += " Interruptable:" + interruptable;
                logMsg += " Channeling:" + channeling;
                logMsg += " Elapsed:" + elapsed + "ms";
                logMsg += " Remaining:" + remaining + "ms";
            }

            Log(logMsg);
        }
    }
}

# Interrupt/Cast Percentage Condition Usage Guide

## Overview
The interrupt system has been refactored into a flexible condition that can be used for various reactive abilities, not just interrupts.

## Components

### 1. UnitCastingAtPercent Condition (01_Conditions.cs)
```csharp
private bool UnitCastingAtPercent(string unit, int minPct, int maxPct = 100)
```
- **Purpose**: Returns true if the specified unit is casting an interruptible spell and the cast progress is within the percentage range
- **Parameters**:
  - `unit`: The unit to check ("target", "boss1", "focus", etc.)
  - `minPct`: Minimum cast percentage (0-100)
  - `maxPct`: Maximum cast percentage (0-100), defaults to 100
- **Returns**: `true` if unit is casting and cast is between minPct and maxPct

### 2. HandleInterruptOnUnit Function (04_Interrupt.cs)
```csharp
private bool HandleInterruptOnUnit(string unit, string spell)
```
- **Purpose**: Interrupt a unit's cast with randomized timing based on settings
- **Parameters**:
  - `unit`: The unit to interrupt ("target", "boss1", etc.)
  - `spell`: The spell to use for interrupting
- **Uses settings**: 
  - "Auto Interrupt" (checkbox)
  - "Interrupt at cast % (min)" (slider)
  - "Interrupt at cast % (max)" (slider)

### 3. ShouldInterruptCast Condition (04_Interrupt.cs)
```csharp
private bool ShouldInterruptCast(string unit, int minPct, int maxPct = 100)
```
- **Purpose**: Alias for `UnitCastingAtPercent` - more semantic name for defensive use cases
- **Parameters**: Same as `UnitCastingAtPercent`

## Usage Examples

### Example 1: Basic Interrupt on Target
```csharp
// In your damage rotation:
if (HandleInterrupt())
    return true;
```

### Example 2: Interrupt Boss1
```csharp
// Interrupt boss1 when they're 40-90% through their cast
if (HandleInterruptOnUnit("boss1", "Wind Shear"))
    return true;
```

### Example 3: Defensive Cooldown on Boss Cast
```csharp
// Use Aura Mastery when boss1 is 30% into casting
if (ShouldInterruptCast("boss1", 30) && CanCastSpell("Aura Mastery"))
{
    Log("Boss casting detected - using Aura Mastery");
    return CastPersonal("Aura Mastery");
}
```

### Example 4: React to Specific Cast Percentage Range
```csharp
// Use defensive when boss is between 20-40% on their cast
if (UnitCastingAtPercent("boss1", 20, 40) && CanCastSpell("Divine Shield"))
{
    Log("Boss dangerous cast detected early - using Divine Shield");
    return CastPersonal("Divine Shield");
}
```

### Example 5: Multiple Boss Unit Checks
```csharp
// Check multiple boss units for dangerous casts
for (int i = 1; i <= 5; i++)
{
    string boss = "boss" + i;

    // React early to dangerous casts (10-30%)
    if (UnitCastingAtPercent(boss, 10, 30) && Inferno.UnitExists(boss))
    {
        if (CanCastSpell("Aura Mastery"))
        {
            Log("Detected dangerous cast from " + boss + " - using Aura Mastery");
            return CastPersonal("Aura Mastery");
        }
    }
}
```

### Example 6: Ally Protection
```csharp
// Protect focus target when boss is casting at them
if (UnitCastingAtPercent("boss1", 40) && CanCastSpell("Blessing of Protection"))
{
    if (Inferno.UnitExists("focus") && !Inferno.IsDead("focus"))
    {
        Log("Protecting focus from boss cast");
        return CastOnUnit("Blessing of Protection", "focus");
    }
}
```

### Example 7: Conditional Interrupt Based on Cast Name
```csharp
// Only interrupt specific spells at certain percentages
if (Inferno.CastingName("target") == "Pyroblast" && UnitCastingAtPercent("target", 70))
{
    if (CanCast("Kick", "target"))
    {
        Log("Interrupting Pyroblast at 70%+");
        Inferno.Cast("Kick");
        return true;
    }
}
```

## Configuration Requirements

To use the interrupt system, your class config (10_Config.cs) needs:

```csharp
// For classes WITH interrupts (DPS/Tank):
private const string INTERRUPT_SPELL = "YourInterruptSpellName";
private Random _rng = new Random();

// Settings in LoadSettings():
Settings.Add(new Setting("Auto Interrupt", true));
Settings.Add(new Setting("Interrupt at cast % (min)", 0, 100, 40));
Settings.Add(new Setting("Interrupt at cast % (max)", 0, 100, 90));
```

For classes without interrupts (healers), you can still use the condition functions:
```csharp
// Minimal config for healers using reactive defensives:
private Random _rng = new Random();
private const string INTERRUPT_SPELL = ""; // Not used but required by component
```

## Tracking System

The interrupt handler uses a dictionary to track each unit independently:
```csharp
private Dictionary<string, (int castID, int targetPct)> _interruptTracking = new Dictionary<string, (int, int)>();
```

This allows:
- Multiple units to be tracked simultaneously (target, boss1, boss2, etc.)
- Each cast gets a new randomized percentage
- Clean state management when casts finish or are interrupted

## Best Practices

1. **Early Detection for Defensives**: Use low percentages (10-30%) for defensive cooldowns to react quickly
2. **Late Interrupt for DPS**: Use higher percentages (40-90%) for interrupts to bait enemy fakes
3. **Range Checks**: Use min/max ranges to create windows of opportunity
4. **Spell Name Filtering**: Combine with `Inferno.CastingName()` to react to specific spells
5. **Priority Systems**: Check dangerous bosses/spells first before falling back to general interrupts

# Quick Reference: UnitCastingAtPercent Condition

## Function Signature
```csharp
private bool UnitCastingAtPercent(string unit, int minPct, int maxPct = 100)
```

## Parameters
- **unit**: Unit to check ("target", "boss1", "boss2", "focus", "arena1", etc.)
- **minPct**: Minimum cast percentage (0-100)
- **maxPct**: Maximum cast percentage (0-100), optional, defaults to 100

## Returns
- `true` if unit is casting an interruptible spell AND cast progress is >= minPct AND <= maxPct
- `false` otherwise

## Quick Examples

### Check if boss1 is 30% into casting
```csharp
if (UnitCastingAtPercent("boss1", 30))
{
    // Use defensive cooldown
}
```

### Check if target is between 70-90% into casting
```csharp
if (UnitCastingAtPercent("target", 70, 90))
{
    // Interrupt late to bait
}
```

### Protect focus when boss is casting
```csharp
if (UnitCastingAtPercent("boss1", 25) && Inferno.UnitExists("focus"))
{
    Inferno.Cast("Blessing of Protection", "focus");
}
```

### Multiple boss checks
```csharp
for (int i = 1; i <= 5; i++)
{
    string boss = "boss" + i;
    if (Inferno.UnitExists(boss) && UnitCastingAtPercent(boss, 30))
    {
        // React to any boss casting
    }
}
```

## Common Patterns

### Early Reaction (10-30%)
Use for defensive cooldowns that need to be preemptive:
```csharp
if (UnitCastingAtPercent("boss1", 10, 30) && CanCastSpell("Aura Mastery"))
    Inferno.Cast("Aura Mastery");
```

### Mid Reaction (30-60%)
Use for standard reactions:
```csharp
if (UnitCastingAtPercent("target", 30, 60) && CanCastSpell("Spell Reflect"))
    Inferno.Cast("Spell Reflect");
```

### Late Reaction (70-90%)
Use for interrupt baiting or last-second reactions:
```csharp
if (UnitCastingAtPercent("target", 70, 90) && CanCast("Kick", "target"))
    Inferno.Cast("Kick");
```

## Combine with Spell Name
```csharp
string spellName = Inferno.CastingName("boss1");
if (spellName == "Pyroblast" && UnitCastingAtPercent("boss1", 20))
{
    // React to specific spell
}
```

## Related Functions

### HandleInterruptOnUnit
```csharp
// Interrupt with randomized timing from settings
HandleInterruptOnUnit("boss1", "Rebuke")
```

### ShouldInterruptCast (alias)
```csharp
// Same as UnitCastingAtPercent, more semantic name
if (ShouldInterruptCast("boss1", 30, 50))
    // Use defensive
```

## Inferno API Used
- `Inferno.CastingID(unit)` - Returns casting spell ID (0 if not casting)
- `Inferno.IsInterruptable(unit)` - Returns true if cast can be interrupted
- `Inferno.CastingElapsed(unit)` - Returns milliseconds elapsed in cast
- `Inferno.CastingRemaining(unit)` - Returns milliseconds remaining in cast
- `Inferno.CastingName(unit)` - Returns name of spell being cast

# Interrupt Handler Refactoring Summary

## What Was Changed

The interrupt system has been refactored from a hardcoded target-only function into a flexible condition system that can work with any unit and be used for various reactive abilities.

## Files Modified

### 1. `poc/Components/01_Conditions.cs`
**Added:**
- `UnitCastingAtPercent(string unit, int minPct, int maxPct = 100)` - Core condition function

**Purpose:** 
- Returns true if specified unit is casting an interruptible spell and cast progress is within percentage range
- Can be used for any unit: "target", "boss1", "focus", "arena1", etc.
- Percentage range allows flexible timing windows

### 2. `poc/Components/04_Interrupt.cs`
**Changed:**
- Replaced simple `_lastCastingID` and `_interruptTargetPct` variables with two dictionaries
- Uses `Dictionary<string, int> _interruptCastID` and `Dictionary<string, int> _interruptTargetPct` for tracking
- Updated `HandleInterrupt()` to use dictionary-based tracking
- Added `HandleInterruptOnUnit(string unit, string spell)` for flexible unit targeting
- Updated `ShouldInterruptCast()` to use new `UnitCastingAtPercent` condition

**Note:** Originally attempted to use `Dictionary<string, (int, int)>` tuple syntax, but this caused C# compilation errors in the target environment. The solution uses two separate dictionaries instead, which is compatible with all C# versions.

**Benefits:**
- Can track multiple units simultaneously (target, boss1, boss2, etc.)
- Each cast gets independent randomization
- Cleaner state management
- More flexible for advanced use cases
- Compatible with older C# versions (no tuple syntax required)

### 3. Class Configuration Files (All `10_Config.cs`)
**Modified files:**
- `poc/Classes/PriestShadow/10_Config.cs`
- `poc/Classes/PriestHoly/10_Config.cs`
- `poc/Classes/PriestDiscPvp/10_Config.cs`
- `poc/Classes/PaladinRetribution/10_Config.cs`
- `poc/Classes/PaladinProtection/10_Config.cs`
- `poc/Classes/PaladinHoly/10_Config.cs`
- `poc/Classes/PaladinHolyPvp/10_Config.cs`

**Changed:**
- Removed `_lastCastingID` and `_interruptTargetPct` variables
- Kept only `_rng` (Random number generator)
- Dictionary tracking is now defined in the universal component

**Before:**
```csharp
private Random _rng = new Random();
private int _lastCastingID = 0;
private int _interruptTargetPct = 0;
```

**After:**
```csharp
private Random _rng = new Random();
```

## New Functionality

### Condition: UnitCastingAtPercent
```csharp
// Check if boss1 is 30% into their cast
if (UnitCastingAtPercent("boss1", 30))
{
    // Use defensive ability
}

// Check if target is between 20-40% into their cast
if (UnitCastingAtPercent("target", 20, 40))
{
    // React within specific window
}
```

### Flexible Interrupts
```csharp
// Interrupt any unit with any spell
if (HandleInterruptOnUnit("boss1", "Wind Shear"))
    return true;

// Still works with original target interrupt
if (HandleInterrupt())
    return true;
```

### Defensive Reactions
```csharp
// Use Aura Mastery when boss1 is 30% into casting
if (UnitCastingAtPercent("boss1", 30) && CanCastSpell("Aura Mastery"))
{
    Log("Boss casting - using Aura Mastery");
    Inferno.Cast("Aura Mastery");
    return true;
}
```

## Use Cases

### 1. **Boss Mechanic Reactions**
React to boss casts at specific percentages for defensive cooldowns

### 2. **Multi-Target Interrupts**
Track and interrupt multiple enemies (arena1, arena2, boss1, boss2)

### 3. **Priority Interrupt Systems**
Check multiple targets with different interrupt timings

### 4. **Spell-Specific Reactions**
Combine with `Inferno.CastingName()` to react differently to different spells

### 5. **Ally Protection**
Detect when boss is casting at allies and use protective cooldowns

## Backward Compatibility

All existing code continues to work:
- `HandleInterrupt()` still works for target interrupts
- Settings-based randomization still functions
- No changes needed to existing rotations

## Documentation Files Created

1. `poc/Components/INTERRUPT_USAGE_EXAMPLES.md` - Comprehensive usage guide
2. `poc/Components/INTERRUPT_CONDITION_EXAMPLES.cs` - Practical code examples

## Configuration Requirements

**For DPS/Tank with interrupts:**
